// Get transcript segments from WayinVideo
const segments = $('4. WayinVideo — Get Transcript Results').item.json.data.transcript || [];

if (segments.length === 0) {
  throw new Error('Transcript is empty — check if the meeting URL is valid and publicly accessible.');
}

// Format transcript with speaker labels and timestamps
const formattedTranscript = segments
  .map(s => {
    const timeInSeconds = Math.floor(s.start / 1000);
    const minutes = Math.floor(timeInSeconds / 60);
    const seconds = timeInSeconds % 60;
    const timestamp = `${minutes}:${seconds.toString().padStart(2, '0')}`;
    return `[${s.speaker} | ${timestamp}] ${s.text.trim()}`;
  })
  .join('\n');

// Calculate duration
const lastSegment = segments[segments.length - 1];
const totalDurationMs = lastSegment?.end || 0;
const totalMinutes = Math.round(totalDurationMs / 60000);

// Unique speakers / attendees
const speakers = [...new Set(segments.map(s => s.speaker))];

// Word count
const wordCount = segments.map(s => s.text).join(' ').split(/\s+/).length;

return [{
  json: {
    formattedTranscript,
    wordCount,
    totalMinutes,
    speakerCount: speakers.length,
    speakers: speakers.join(', '),
    meetingTitle: $('1. Form — Meeting URL + Details').item.json['Meeting Title'],
    teamName: $('1. Form — Meeting URL + Details').item.json['Team Name'],
    meetingDate: $('1. Form — Meeting URL + Details').item.json['Meeting Date'],
    slackChannel: $('1. Form — Meeting URL + Details').item.json['Slack Channel Name'],
    recordingUrl: $('1. Form — Meeting URL + Details').item.json['Meeting Recording URL']
  }
}];

// Parse AI output into structured sections for Slack
const output = $input.first().json.output || '';

// Extract each section using regex
const summaryMatch = output.match(/MEETING SUMMARY:\s*([\s\S]*?)(?=\nACTION ITEMS:|$)/);
const actionItemsMatch = output.match(/ACTION ITEMS:\s*([\s\S]*?)(?=\nDECISIONS MADE:|$)/);
const decisionsMatch = output.match(/DECISIONS MADE:\s*([\s\S]*?)(?=\nKEY DISCUSSION POINTS:|$)/);
const keyPointsMatch = output.match(/KEY DISCUSSION POINTS:\s*([\s\S]*?)(?=\nNEXT STEPS:|$)/);
const nextStepsMatch = output.match(/NEXT STEPS:\s*([\s\S]*)$/);

const meetingSummary = summaryMatch ? summaryMatch[1].trim() : 'No summary available';
const actionItems = actionItemsMatch ? actionItemsMatch[1].trim() : 'None identified';
const decisions = decisionsMatch ? decisionsMatch[1].trim() : 'None recorded';
const keyPoints = keyPointsMatch ? keyPointsMatch[1].trim() : 'None recorded';
const nextSteps = nextStepsMatch ? nextStepsMatch[1].trim() : 'None mentioned';

// Get metadata from previous node
const meetingTitle = $('7. Code — Format Transcript').item.json.meetingTitle;
const teamName = $('7. Code — Format Transcript').item.json.teamName;
const meetingDate = $('7. Code — Format Transcript').item.json.meetingDate;
const totalMinutes = $('7. Code — Format Transcript').item.json.totalMinutes;
const speakers = $('7. Code — Format Transcript').item.json.speakers;
const recordingUrl = $('7. Code — Format Transcript').item.json.recordingUrl;
const slackChannel = $('7. Code — Format Transcript').item.json.slackChannel;

// Build Slack Block Kit message
const slackBlocks = [
  {
    "type": "header",
    "text": {
      "type": "plain_text",
      "text": `Meeting Summary — ${meetingTitle}`,
      "emoji": true
    }
  },
  {
    "type": "section",
    "fields": [
      {
        "type": "mrkdwn",
        "text": `*Team:*\n${teamName}`
      },
      {
        "type": "mrkdwn",
        "text": `*Date:*\n${meetingDate}`
      },
      {
        "type": "mrkdwn",
        "text": `*Duration:*\n${totalMinutes} minutes`
      },
      {
        "type": "mrkdwn",
        "text": `*Attendees:*\n${speakers}`
      }
    ]
  },
  {
    "type": "divider"
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Meeting Summary*\n${meetingSummary}`
    }
  },
  {
    "type": "divider"
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Action Items*\n${actionItems}`
    }
  },
  {
    "type": "divider"
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Decisions Made*\n${decisions}`
    }
  },
  {
    "type": "divider"
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Key Discussion Points*\n${keyPoints}`
    }
  },
  {
    "type": "divider"
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Next Steps*\n${nextSteps}`
    }
  },
  {
    "type": "divider"
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*Full Recording*\n<${recordingUrl}|Watch Recording>`
    }
  },
  {
    "type": "context",
    "elements": [
      {
        "type": "mrkdwn",
        "text": `_Auto-generated by n8n + WayinVideo + GPT-4o-mini_`
      }
    ]
  }
];

return [{
  json: {
    slackBlocks: JSON.stringify(slackBlocks),
    slackChannel,
    meetingTitle,
    meetingSummary,
    actionItems,
    decisions,
    keyPoints,
    nextSteps,
    meetingDate,
    totalMinutes
  }
}];
